 4→export async function requireStudent() {
 5→  const { userId } = await auth();
 6→  if (!userId) {
 7→    throw new Error("Unauthorized");
 8→  }
 9→
10→  const student = await prisma.student.findUnique({
11→    where: { clerkId: userId },
12→    include: {
13→      school: true,
14→      privacySettings: true,
15→      notificationPrefs: true,
16→    },
17→  });
18→
19→  if (!student) {
20→    throw new Error("Student not found");
21→  }
22→
23→  return student;
24→}
