  1→import { headers } from "next/headers";
  2→import { Webhook } from "svix";
  3→import { WebhookEvent } from "@clerk/nextjs/server";
  4→import { prisma } from "@compass/db";
  5→import { NextResponse } from "next/server";
  6→
  7→export async function POST(req: Request) {
  8→  const WEBHOOK_SECRET = process.env.CLERK_WEBHOOK_SECRET;
  9→  if (!WEBHOOK_SECRET) {
 10→    throw new Error("CLERK_WEBHOOK_SECRET is not set");
 11→  }
 12→
 13→  // Get svix headers
 14→  const headerPayload = await headers();
 15→  const svix_id = headerPayload.get("svix-id");
 16→  const svix_timestamp = headerPayload.get("svix-timestamp");
 17→  const svix_signature = headerPayload.get("svix-signature");
 18→
 19→  if (!svix_id || !svix_timestamp || !svix_signature) {
 20→    return NextResponse.json({ error: "Missing svix headers" }, { status: 400 });
 21→  }
 22→
 23→  const payload = await req.json();
 24→  const body = JSON.stringify(payload);
 25→
 26→  const wh = new Webhook(WEBHOOK_SECRET);
 27→  let evt: WebhookEvent;
 28→
 29→  try {
 30→    evt = wh.verify(body, {
 31→      "svix-id": svix_id,
 32→      "svix-timestamp": svix_timestamp,
 33→      "svix-signature": svix_signature,
 34→    }) as WebhookEvent;
 35→  } catch {
 36→    return NextResponse.json({ error: "Invalid webhook" }, { status: 400 });
 37→  }
 38→
 39→  const { type, data } = evt;
 40→
 41→  if (type === "user.created" || type === "user.updated") {
 42→    const { id: clerkId, email_addresses, first_name, last_name, public_metadata } = data;
 43→    const email = email_addresses[0]?.email_address;
 44→    const role = (public_metadata?.role as string) ?? "STUDENT";
 45→
 46→    if (!email) {
 47→      return NextResponse.json({ error: "No email" }, { status: 400 });
 48→    }
 49→
 50→    if (role === "COUNSELOR") {
 51→      await prisma.counselor.upsert({
 52→        where: { clerkId },
 53→        update: {
 54→          email,
 55→          firstName: first_name ?? "",
 56→          lastName: last_name ?? "",
 57→        },
 58→        create: {
 59→          clerkId,
 60→          email,
 61→          firstName: first_name ?? "",
 62→          lastName: last_name ?? "",
 63→          schoolId: (public_metadata?.schoolId as string) ?? "default-school",
 64→        },
 65→      });
 66→    } else {
 67→      // Default to STUDENT
 68→      await prisma.student.upsert({
 69→        where: { clerkId },
 70→        update: {
 71→          email,
 72→          firstName: first_name ?? "",
 73→          lastName: last_name ?? "",
 74→        },
 75→        create: {
 76→          clerkId,
 77→          email,
 78→          firstName: first_name ?? "",
 79→          lastName: last_name ?? "",
 80→          schoolId: (public_metadata?.schoolId as string) ?? undefined,
 81→        },
 82→      });
 83→
 84→      // Create default privacy settings
 85→      const student = await prisma.student.findUnique({ where: { clerkId } });
 86→      if (student) {
 87→        await prisma.studentPrivacySettings.upsert({
 88→          where: { studentId: student.id },
 89→          update: {},
 90→          create: { studentId: student.id },
 91→        });
 92→
 93→        await prisma.notificationPreferences.upsert({
 94→          where: { studentId: student.id },
 95→          update: {},
 96→          create: { studentId: student.id },
 97→        });
 98→      }
 99→    }
100→  }
101→
102→  if (type === "user.deleted") {
103→    const { id: clerkId } = data;
104→    // Cascade deletes via DB constraints
105→    await prisma.student.deleteMany({ where: { clerkId: clerkId! } });
106→    await prisma.counselor.deleteMany({ where: { clerkId: clerkId! } });
107→  }
108→
109→  return NextResponse.json({ received: true });
110→}
